Rules.InvariantScript:
Clear(colAUDRecords);
If(
    gblAppLoadOffline,
    SaveData(
        colAUDRecords,
        "localAUDRecords"
    )
);
UpdateContext({locShowPopUp: ""});
Patch(
    Jobs,
    ShowColumns(
        colCdsJobs,
        Job,
        Completed,
        'Job Package: Send Documents?',
        'Lead Test: Send Document?',
        'Job Finished: Send Email?'
    )
);
Reset(tmr_Saving_Navigate);
UpdateContext({locStartTimer: true})

// Advance to Job Update
Select(btn_Saving_Update__Jobs);
UpdateContext({locBoolean_ShowSavePrompt: false});

Navigate(
    'Loading Screen',
    ScreenTransition.Fade,
    {locLoadingSkipLocal: true}
);
UpdateContext({locStartTimer: false});

// Start
Collect(
    colSaveProgress,
    {
        ProgressValue: 0,
        ProgressText: "Saving Your Data"
    }
);
Clear(colProgressBar);
ForAll(
    Sequence(CountRows(colAUDRecords)+1),
    Collect(
        colProgressBar,
        {Saved: false}
    )
);
If(
    Connection.Connected,
    // Next Step
    If(
        gblAppAutoAdvance,
        Select(btn_Saving_Add__JobRooms)
    ),
    UpdateContext({locShowPopUp: "Not Connected"})
)

// Create Job Rooms
With(
    {
        // Get job rooms with add operation
        varJobRooms:
            Filter(
                colCdsJobRooms,
                'Job Room' in Filter(
                    colAUDRecords,
                    Type = "colCdsJobRooms",
                    Operation = "A"
                ).RecordRef
            )
    },
    If(
        !IsEmpty(varJobRooms),
        // Collect Progress Record
        Collect(
            colSaveProgress,
            {
                ProgressValue: 1,
                ProgressText: "Creating Job Rooms"
            }
        );
        Clear(colParentRecords);
        ForAll(
            // Filter records to be added
            varJobRooms As tblRecordLoop,
            With(
                {
                    // Write new records to datasource, excluding certain columns
                    varNewRecord: Patch(
                        'Job Rooms',
                        Defaults('Job Rooms'),
                        First(
                            DropColumns(
                                Table(tblRecordLoop),
                                appJobIdText,
                                appJobRoomIdText,
                                'Job Room'
                            )
                        )
                    )
                },
                If(
                    IsEmpty(Errors('Job Rooms')),
                    Collect(
                        colParentRecords,
                        {
                            Type: "colCdsJobRooms",
                            OriginalGUID: tblRecordLoop.'Job Room',
                            NewGUID: varNewRecord.'Job Room'
                        }
                    )
                )
            )
        );
        // Update Child Records for new reference
        Refresh('Job Rooms');       
        ForAll(
            colParentRecords,
            With(
                {varParentRecord: LookUp('Job Rooms', 'Job Room'=colParentRecords[@NewGUID])},
                // Update Job Room GUID
                Patch(
                    colCdsJobRooms,
                    LookUp(colCdsJobRooms, 'Job Room'=colParentRecords[@OriginalGUID]),
                    varParentRecord
                );
                // Update Child Records for new reference
                // Job Entries
                UpdateIf(
                    colCdsJobEntries,
                    'Job Room'.'Job Room' = colParentRecords[@OriginalGUID],
                    {'Job Room': varParentRecord}
                );
                // Window Mulls
                UpdateIf(
                    colCdsWindowMulls,
                    'Job Room'.'Job Room' = colParentRecords[@OriginalGUID],
                    {'Job Room': varParentRecord}
                )
            );
            // Remove from collection of records which would be processed
            RemoveIf(
                colAUDRecords,
                And(
                    Type = "colCdsJobRooms",
                    RecordRef = colParentRecords[@OriginalGUID],
                    Operation = "A"
                )
            );
        );
        // update progress bar
        Update(
            colProgressBar,
            LookUp(colProgressBar, Not(Saved)),
            {Saved: true}
        )
    );
    // Save Data
    If(
        gblAppLoadOffline,
        SaveData(
            colAUDRecords,
            "localAUDRecords"
        );
        SaveData(
            colCdsJobRooms,
            "localCdsJobRooms"
        );
        SaveData(
            colCdsJobEntries,
            "localCdsJobEntries"
        );
        SaveData(
            colCdsWindowMulls,
            "localCdsWindowMulls"
        );
    )
);
// Next Step
If(
    gblAppAutoAdvance,
    Select(btn_Saving_Add__JobEntries)
);

// Create Job Entries
With(
    {
        varJobEntries:
            Filter(
                colCdsJobEntries,
                'Job Entry' in Filter(
                    colAUDRecords,
                    Type = "colCdsJobEntries",
                    Operation = "A"
                ).RecordRef,
                !('Job Room'.'Job Room' in Filter(colAUDRecords, Type="colCdsJobRooms").RecordRef),
                !('Window Mull'.'Window Mulls' in Filter(colAUDRecords, Type="colCdsWindowMulls").RecordRef)
            )
    },
    If(
        !IsEmpty(varJobEntries),
        // Collect Progress Record
        Collect(
            colSaveProgress,
            {
                ProgressValue: 2,
                ProgressText: "Creating Job Entries"
            }
        );
        Clear(colParentRecords);
        ForAll(
            // For all records to be added, excluding columns which should not be used in Add
            varJobEntries As tblRecordLoop,
            With(
                { 
                    // Write new records to datasource
                    varNewRecord: Patch(
                        'Job Entries',
                        Defaults('Job Entries'),
                        First(
                            DropColumns(
                                Table(tblRecordLoop),
                                appFields,
                                appJobIdText,
                                appJobRoomIdText,
                                '''Window Choice''',
                                'Job Entry',
                                'Measurement (Sales)',
                                'Measurement (Tech)'
                            )
                        )
                    )
                },
                If(
                    IsEmpty(Errors('Job Entries')),
                    Collect(
                        colParentRecords,
                        {
                            Type: "colCdsJobEntries",
                            OriginalGUID: tblRecordLoop.'Job Entry',
                            NewGUID: varNewRecord.'Job Entry'
                        }
                    )
                );
                If(
                    !IsEmpty(Errors('Job Entries')),
                    Notify($"Job Entries: {First(Errors('Job Entries')).Error} {First(Errors('Job Entries')).Message} {First(Errors('Job Entries')).Column}")
                )
            )
        );
        //// Update child records with new parent GUID 
        Refresh('Job Entries');
        ForAll(
            colParentRecords,
            With(
                {varParentRecord: LookUp('Job Entries', 'Job Entry'=colParentRecords[@NewGUID])},
                // Update job entries GUID
                Patch(
                    colCdsJobEntries,
                    LookUp(colCdsJobEntries, 'Job Entry'=colParentRecords[@OriginalGUID]),
                    varParentRecord
                );
                // Job Entry Selections
                UpdateIf(
                    colCdsJobEntrySelections,
                    'Job Entry'.'Job Entry' = colParentRecords[@OriginalGUID],
                    {'Job Entry': varParentRecord}
                );
                // Job Photos
                UpdateIf(
                    colCdsJobPhotos,
                    'Job Entry'.'Job Entry' = colParentRecords[@OriginalGUID],
                    {'Job Entry': varParentRecord}
                );
                // Window Measurements
                UpdateIf(
                    colCdsWindowMeasurements,
                    'Job Entry'.'Job Entry' = colParentRecords[@OriginalGUID],
                    {'Job Entry': varParentRecord}
                );
                // Window Mulls
                UpdateIf(
                    colCdsWindowMeasurements,
                    'Job Entry'.'Job Entry' = colParentRecords[@OriginalGUID],
                    {'Job Entry': varParentRecord}
                );
                // Remove from list of new records
                RemoveIf(
                    colAUDRecords,
                    And(
                        Type = "colCdsJobEntries",
                        RecordRef = colParentRecords[@OriginalGUID],
                        Operation = "A"
                    )
                )
            )
        );
        // update progress bar
        Update(
            colProgressBar,
            LookUp(colProgressBar, Not(Saved)),
            {Saved: true}
        )
    );
    // Save Data
    IfError( // This line of code is added to hide the errors

    If(
        gblAppLoadOffline,
        SaveData(
            colAUDRecords,
            "localAUDRecords"
        );
        SaveData(
            colCdsJobEntries,
            "localCdsJobEntries"
        );
        SaveData(
            colCdsJobEntrySelections,
            "localCdsJobEntrySelections"
        );
        SaveData(
            colCdsJobPhotos,
            "localCdsJobPhotos"
        );
        SaveData(
            colCdsWindowMeasurements,
            "localCdsWindowMeasurements"
        );
    )
    ,Blank())  // This line of code is added to hide the errors
);
// Next Step
If(
    gblAppAutoAdvance,
    Select(btn_Saving_Add__WindowMulls)
);

// Create Window Mulls
With(
    {
        // Get window mulls with add operation
        varWindowMulls:
        Filter(
            colCdsWindowMulls,
            'Window Mulls' in Filter(
                colAUDRecords,
                Type = "colCdsWindowMulls",
                Operation = "A"
            ).RecordRef,
            !('Job Room'.'Job Room' in Filter(colAUDRecords, Type="colCdsJobRooms").RecordRef)
        )
    },
    If(
        !IsEmpty(varWindowMulls),
        // Collect Progress Record
        Collect(
            colSaveProgress,
            {
                ProgressValue: 2,
                ProgressText: "Creating Window Mulls"
            }
        );
        Clear(colParentRecords);
        // Process Add (Create) Records
        ForAll(
            // Filter records to be added
            varWindowMulls As tblRecordLoop,
            With(
                {
                    // Write new records to datasource, excluding certain columns
                    varNewRecord: Patch(
                        'Window Mulls',
                        Defaults('Window Mulls'),
                        First(
                            DropColumns(
                                Table(tblRecordLoop),
                                'Window Mulls',
                                appJobRoomIdText
                            )
                        )
                    )
                },
                If(
                    IsEmpty(Errors('Window Mulls')),
                    Collect(
                        colParentRecords,
                        {
                            Type: "colCdsWindowMulls",
                            OriginalGUID: tblRecordLoop.'Window Mulls',
                            NewGUID: varNewRecord.'Window Mulls'
                        }
                    )
                )
            )
        );
        // Update Child Records for new reference
        Refresh('Window Mulls');       
        ForAll(
            colParentRecords,
            With(
                {varParentRecord: LookUp('Window Mulls', 'Window Mulls'=colParentRecords[@NewGUID])},
                // Update Window Mulls GUID
                Patch(
                    colCdsWindowMulls,
                    LookUp(colCdsWindowMulls, 'Window Mulls'=colParentRecords[@OriginalGUID]),
                    varParentRecord
                );
                // Job Entries
                UpdateIf(
                    colCdsJobEntries,
                    'Window Mull'.'Window Mulls'=colParentRecords[@OriginalGUID],
                    {'Window Mull': varParentRecord}
                );
                // Window Measurements
                UpdateIf(
                    colCdsWindowMeasurements,
                    'Window Mull'.'Window Mulls'=colParentRecords[@OriginalGUID],
                    {'Window Mull': varParentRecord}
                );
                // Remove from collection of records which would be processed
                RemoveIf(
                    colAUDRecords,
                    And(
                        Type = "colCdsWindowMulls",
                        RecordRef = colParentRecords[@OriginalGUID],
                        Operation = "A"
                    )
                )
            );
            // update progress bar
            Update(
                colProgressBar,
                LookUp(colProgressBar, Not(Saved)),
                {Saved: true}
            )
        );
        // Save Data
        If(
            gblAppLoadOffline,
            SaveData(
                colAUDRecords,
                "localAUDRecords"
            );
            SaveData(
                colCdsWindowMulls,
                "localCdsWindowMulls"
            );
            SaveData(
                colCdsJobEntries,
                "localCdsJobEntries"
            );
            SaveData(
                colCdsWindowMeasurements,
                "localCdsWindowMeasurements"
            );
        )
    )
);
// Next Step
If(
    gblAppAutoAdvance,
    Select(btn_Saving_Add__JobEntrySelections)
);

// Create Job Entry Selections
With(
    {
        varJobEntrySelections:
            Filter(
                colCdsJobEntrySelections,
                'Job Entry Selection' in Filter(
                    colAUDRecords,
                    Type = "colCdsJobEntrySelections",
                    Operation = "A"
                ).RecordRef,
                !('Job Entry'.'Job Entry' in Filter(colAUDRecords, Type="colCdsJobEntries").RecordRef)
            )
    },
    If(
        !IsEmpty(varJobEntrySelections),
        // Collect Progress Record
        Collect(
            colSaveProgress,
            {
                ProgressValue: 4,
                ProgressText: "Creating Job Entry Selections"
            }
        );
        Clear(colParentRecords);
        ForAll(
            // For all records to be added, excluding columns which should not be used in Add
            varJobEntrySelections As tblRecordLoop,
            With(
                {
                    // Write new records to datasource
                    varNewRecord: Patch(
                        'Job Entry Selections',
                        Defaults('Job Entry Selections'),
                        First(
                            DropColumns(
                                Table(tblRecordLoop),
                                appAttributeName,
                                'Job Entry Selection'
                            )
                        )
                    )
                },
                With(
                    {varErrors: Errors('Job Entry Selections')}, 
                    If(
                        !IsEmpty(varErrors),
                        Notify(
                            First(varErrors).Error&Char(10)&
                            First(varErrors).Record.'Job Entry Selection'&Char(10)&
                            First(varErrors).Column&Char(10)&
                            First(varErrors).Message
                        )
                    )
                );
                If(
                    IsEmpty(Errors('Job Entry Selections')),
                    Collect(
                        colParentRecords,
                        {
                            Type: "colCdsJobEntrySelections",
                            OriginalGUID: tblRecordLoop.'Job Entry Selection',
                            NewGUID: varNewRecord.'Job Entry Selection'
                        }
                    )
                );
                If(
                    !IsEmpty(Errors('Job Entry Selections')),
                    Notify($"Job Entry Selections: {First(Errors('Job Entry Selections')).Error} {First(Errors('Job Entry Selections')).Message} {First(Errors('Job Entry Selections')).Column}")
                )
            )
        );
        ForAll(
            colParentRecords,
            With(
                {varParentRecord: LookUp('Job Entry Selections', 'Job Entry Selection'=colParentRecords[@NewGUID])},
                // Update job entry selection GUID
                Patch(
                    colCdsJobEntrySelections,
                    LookUp(colCdsJobEntrySelections, 'Job Entry Selection'=colParentRecords[@OriginalGUID]),
                    varParentRecord
                );
                // Remove from list of new records
                RemoveIf(
                    colAUDRecords,
                    And(
                        Type = "colCdsJobEntrySelections",
                        RecordRef = colParentRecords[@OriginalGUID],
                        Operation = "A"
                    )
                );
                // update progress bar
                Update(
                    colProgressBar,
                    LookUp(colProgressBar, Not(Saved)),
                    {Saved: true}
                )
            )
        );
        // Save Data
        If(
            gblAppLoadOffline,
            SaveData(
                colAUDRecords,
                "localAUDRecords"
            );
            SaveData(
                colCdsJobEntrySelections,
                "localCdsJobEntrySelections"
            )
        );
    )
);
If(
    gblAppAutoAdvance,
    Select(btn_Saving_Add__JobLaborItems)
);

// Create Job Labor Items
With(
    {
        varJobLaborItems:
            Filter(
            colCdsJobLaborItems,
            'Job Labor Item' in Filter(
                colAUDRecords,
                Type = "colCdsJobLaborItems",
                Operation = "A"
            ).RecordRef
        )
    },
    If(
        !IsEmpty(varJobLaborItems),
        // Collect Progress Record
        Collect(
            colSaveProgress,
            {
                ProgressValue: 5,
                ProgressText: "Creating Job Labor Items"
            }
        );
        Clear(colParentRecords);
        ForAll(
            // For all records to be added, excluding columns which should not be used in Add
            varJobLaborItems As tblRecordLoop,
            With(
                {
                    // Write new records to datasource
                    varNewRecord: Patch(
                        'Job Labor Items',
                        Defaults('Job Labor Items'),
                        First(
                            DropColumns(
                                Table(tblRecordLoop),
                                'Job Labor Item',
                                appJobIDText
                            )
                        )
                    )
                },
                If(
                    IsEmpty(Errors('Job Labor Items')),
                    Collect(
                        colParentRecords,
                        {
                            Type: "colCdsJobLaborItems",
                            OriginalGUID: tblRecordLoop.'Job Labor Item',
                            NewGUID: varNewRecord.'Job Labor Item'
                        }
                    )
                )
            )
        );
        ForAll(
            colParentRecords,
            // Update job labor items GUID
            Patch(
                colCdsJobLaborItems,
                LookUp(colCdsJobLaborItems, 'Job Labor Item'=colParentRecords[@OriginalGUID]),
                LookUp('Job Labor Items', 'Job Labor Item'=colParentRecords[@NewGUID])
            );
            // Remove from list of new records
            RemoveIf(
                colAUDRecords,
                And(
                    Type = "colCdsJobLaborItems",
                    RecordRef = colParentRecords[@OriginalGUID],
                    Operation = "A"
                )
            );
            // update progress bar
            Update(
                colProgressBar,
                LookUp(colProgressBar, Not(Saved)),
                {Saved: true}
            )
        );
        If(
            gblAppLoadOffline,
            // Save data
            SaveData(
                colAUDRecords,
                "localAUDRecords"
            );
            SaveData(
                colCdsJobLaborItems,
                "localCdsJobLaborItems"
            )
        )
    )
);
// Next screen
If(
    gblAppAutoAdvance,
    Select(btn_Saving_Add__JobMaterialItems)
);

// Create Job Material Items
With(
    {
        varJobMaterialItems:
        Filter(
            colCdsJobMaterialItems,
            'Job Material Item' in Filter(
                colAUDRecords,
                Type = "colCdsJobMaterialItems",
                Operation = "A"
            ).RecordRef
        )
    },
    If(
        !IsEmpty(varJobMaterialItems),      
        // Collect Progress Record
        Collect(
            colSaveProgress,
            {
                ProgressValue: 6,
                ProgressText: "Creating Job Material Items"
            }
        );
        Clear(colParentRecords);
        ForAll(
            // For all records to be added, excluding columns which should not be used in Add
            varJobMaterialItems As tblRecordLoop,
            With(
                {
                    // Write new records to datasource
                    varNewRecord: Patch(
                        'Job Material Items',
                        Defaults('Job Material Items'),
                        First(
                            DropColumns(
                                Table(tblRecordLoop),
                                'Job Material Item',
                                appJobIDText
                            )
                        )
                    )
                },
                If(
                    IsEmpty(Errors('Job Material Items')),
                    Collect(
                        colParentRecords,
                        {
                            Type: "colCdsJobMaterialItems",
                            OriginalGUID: tblRecordLoop.'Job Material Item',
                            NewGUID: varNewRecord.'Job Material Item'
                        }
                    )
                )
            )
        );
        ForAll(
            colParentRecords,
            // Update job material items GUID
            Patch(
                colCdsJobMaterialItems,
                LookUp(colCdsJobMaterialItems, 'Job Material Item'=colParentRecords[@OriginalGUID]),
                LookUp('Job Material Items', 'Job Material Item'=colParentRecords[@NewGUID])
            );
            // Remove from list of new records
            RemoveIf(
                colAUDRecords,
                And(
                    Type = "colCdsJobMaterialItems",
                    RecordRef = colParentRecords[@OriginalGUID],
                    Operation = "A"
                )
            );
            // update progress bar
            Update(
                colProgressBar,
                LookUp(colProgressBar, Not(Saved)),
                {Saved: true}
            )
        );
        If(
            gblAppLoadOffline,
            // Save data
            SaveData(
                colAUDRecords,
                "localAUDRecords"
            );
            SaveData(
                colCdsJobMaterialItems,
                "localCdsJobMaterialItems"
            );
        )
    )
);
// Next screen
If(
    gblAppAutoAdvance,
    Select(btn_Saving_Add__WindowMeasurements)
);

// Create Window Measurements
With(
    {
        varWindowMeasurements: Filter(
            colCdsWindowMeasurements,
            'Window Measurement' in Filter(
                colAUDRecords,
                Type = "colCdsWindowMeasurements",
                Operation = "A"
            ).RecordRef,
            !('Job Entry'.'Job Entry' in Filter(
                colAUDRecords,
                Type = "colCdsJobEntries"
            ).RecordRef)
        )
    },
    If(
        !IsEmpty(varWindowMeasurements),
        // Collect Progress Record
        Collect(
            colSaveProgress,
            {
                ProgressValue: 6,
                ProgressText: "Creating Window Measurements"
            }
        );
        Clear(colParentRecords);
        // Process Add (Create) Records
ForAll(
            // Filter records to be added
            varWindowMeasurements As tblRecordLoop,
            With(
                {
                    // Write new records to datasource, excluding certain columns
                    varNewRecord: Patch(
                        'Window Measurements',
                        Defaults('Window Measurements'),
                        First(
                            DropColumns(
                                Table(tblRecordLoop),
                                'Window Measurement'
                            )
                        )
                    )
                },
                If(
                    IsEmpty(Errors('Window Measurements')),
                    Collect(
                        colParentRecords,
                        {
                            Type: "colCdsWindowMeasurements",
                            OriginalGUID: tblRecordLoop.'Window Measurement',
                            NewGUID: varNewRecord.'Window Measurement'
                        }
                    )
                );
                If(
                    !IsEmpty(Errors('Window Measurements')),
                    Notify($"Window Measurements: {First(Errors('Window Measurements')).Error} {First(Errors('Window Measurements')).Message} {First(Errors('Window Measurements')).Column}")
                )
            )
        );
        ForAll(
            colParentRecords,
            With(
                {
                    varParentRecord: LookUp(
                        'Window Measurements',
                        'Window Measurement' = colParentRecords[@NewGUID]
                    )
                },
                // Update window measurements GUID
                Patch(
                    colCdsWindowMeasurements,
                    LookUp(
                        colCdsWindowMeasurements,
                        'Window Measurement' = colParentRecords[@OriginalGUID]
                    ),
                    LookUp(
                        'Window Measurements',
                        'Window Measurement' = colParentRecords[@NewGUID]
                    )
                );
                // Job Photos
UpdateIf(
                    colCdsJobPhotos,
                    'Window Measurement'.'Window Measurement' = colParentRecords[@OriginalGUID],
                    {'Window Measurement': varParentRecord}
                );
                // Remove from collection of records which would be processed
RemoveIf(
                    colAUDRecords,
                    And(
                        Type = "colCdsWindowMeasurements",
                        RecordRef = colParentRecords[@OriginalGUID],
                        Operation = "A"
                    )
                )
            );
            // update progress bar
Update(
                colProgressBar,
                LookUp(
                    colProgressBar,
                    Not(Saved)
                ),
                {Saved: true}
            )
        );
        // Save Data
If(
            gblAppLoadOffline,
            SaveData(
                colAUDRecords,
                "localAUDRecords"
            );
            SaveData(
                colCdsWindowMeasurements,
                "localCdsWindowMeasurements"
            );
            SaveData(
                colCdsJobEntries,
                "localCdsJobPhotos"
            )
        )
    )
);
// Next Step
If(
    gblAppAutoAdvance,
    Select(btn_Saving_Update__JobRooms)
);

// Update Job Rooms
With(
    {
        varJobRooms: 
            Filter(
                colCdsJobRooms,
                'Job Room' in Filter(
                    colAUDRecords,
                    Type = "colCdsJobRooms",
                    Operation = "U"
                ).RecordRef
            )
    },
    If(
        !IsEmpty(varJobRooms),
        // Collect Progress Record
        Collect(
            colSaveProgress,
            {
                ProgressValue: 8,
                ProgressText: "Updating Job Rooms"
            }
        );
        // Process Update Records
        With(
            {
                varPatchedRecords:
                Patch(
                    'Job Rooms',
                    ShowColumns(
                        varJobRooms,
                        Floor,
                        Job,
                        'Job Room',
                        Name,
                        Room
                    )
                )
            },
            // remove records from tracking
            RemoveIf(
                colAUDRecords,
                And(
                    Type = "colCdsJobRooms",
                    RecordRef in varPatchedRecords.'Job Room',
                    Operation = "U"
                )
            ) 
        );
        ForAll(
            varJobRooms,
            // update progress bar
            Update(
                colProgressBar,
                LookUp(colProgressBar, Not(Saved)),
                {Saved: true}
            )
        );
        // Save data
        If(
            gblAppLoadOffline,
            SaveData(
                colAUDRecords,
                "localAUDRecords"
            );
            SaveData(
                colCdsJobRooms,
                "localCdsJobRooms"
            );
        )
    )
);
// Next Step
If(
    gblAppAutoAdvance,
    Select(btn_Saving_Update__JobEntries)
);

// Update Job Entries
With(
    {
        varJobEntries: 
            Filter(
                colCdsJobEntries,
                'Job Entry' in Filter(
                    colAUDRecords,
                    Type = "colCdsJobEntries",
                    Operation = "U"
                ).RecordRef
            )
    },
    If(
        !IsEmpty(varJobEntries),
        // Collect Progress Record
        Collect(
            colSaveProgress,
            {
                ProgressValue: 9,
                ProgressText: "Updating Job Entries"
            }
        );
        // Process Update Records
        With(
            {
                varPatchedRecords:
                Patch(
                    'Job Entries',
                    ShowColumns(
                        varJobEntries,
                        'Job Entry',
                        Job,
                        Name,
                        Completed,
                        'Job Room',
                        'Lead Test: Exterior Component',
                        'Lead Test: Exterior Result',
                        'Lead Test: Exterior Swab Number',
                        'Lead Test: Interior Component',
                        'Lead Test: Interior Result',
                        'Lead Test: Interior Swab Number',
                        Notes,
                        'Room: Description',
                        'Room: Floor',
                        'Room: Type',
                        'Window Choice',
                        'Window Mull'
                    )
                )
